import { pool } from "./storage";

interface EncyclopediaEntry {
  profession: string;
  slug: string;
  title: string;
  category: string;
  status: string;
  seoTitle: string;
  seoDescription: string;
  seoKeywords: string[];
  overview: string;
  mechanismPhysiology: string;
  clinicalRelevance: string;
  signsSymptoms: string;
  assessment: string;
  management: string;
  complications: string;
  clinicalPearls: string[];
  examPitfalls: string[];
  faqJson: { question: string; answer: string }[];
}

function makeEntry(
  slug: string,
  title: string,
  category: string,
  overview: string,
  mechanism: string,
  clinical: string,
  signs: string,
  assessment: string,
  management: string,
  complications: string,
  pearls: string[],
  pitfalls: string[],
  faq: { question: string; answer: string }[],
  keywords: string[]
): EncyclopediaEntry {
  return {
    profession: "addictions",
    slug,
    title,
    category,
    status: "published",
    seoTitle: `${title} — Addictions Counseling Encyclopedia`,
    seoDescription: overview.substring(0, 155) + "...",
    seoKeywords: keywords,
    overview,
    mechanismPhysiology: mechanism,
    clinicalRelevance: clinical,
    signsSymptoms: signs,
    assessment,
    management,
    complications,
    clinicalPearls: pearls,
    examPitfalls: pitfalls,
    faqJson: faq,
  };
}

